parameters.value:
query {
  posts(first: 5) {
    edges {
      node {
        name
        tagline
        description
        website
        topics {
          edges {
            node {
              name
            }
          }
        }
        makers {
          name
        }
      }
    }
  }
}

parameters.jsCode:
const splitOutItems = $('Split Post Edges').all();
const results = [];

const BLOCKED_PATTERNS = [
  'apps.apple.com', 'itunes.apple.com', 'play.google.com', 'apps.shopify.com',
  'chrome.google.com', 'chromewebstore.google.com', 'addons.mozilla.org',
  'marketplace.visualstudio.com', 'apps.microsoft.com',
  'linktr.ee', 'bio.link', 'beacons.ai', 'linkin.bio', 'solo.to',
  'twitter.com', 'x.com', 'instagram.com', 'facebook.com', 'linkedin.com',
  'youtube.com', 'tiktok.com', 'discord.gg', 'discord.com', 't.me', 'reddit.com',
  'github.com', 'gitlab.com', 'npmjs.com', 'pypi.org',
  'notion.site', 'framer.website', 'framer.app', 'webflow.io', 'carrd.co',
  'vercel.app', 'netlify.app', 'glide.page', 'bubbleapps.io', 'softr.app',
  'bit.ly', 'tinyurl.com', 't.co', 'lnkd.in', 'buff.ly',
  'producthunt.com', 'medium.com', 'substack.com'
];

for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i];
  const originalNode = splitOutItems[i].json.node;

  // Normalize location header: could be string, array, or missing
  let locationHeader = item.json.headers?.location;
  if (Array.isArray(locationHeader)) {
    locationHeader = locationHeader[0];
  }
  let rawUrl = (locationHeader || "").toString().trim();

  // If no redirect happened, fall back to the original PH URL
  if (!rawUrl) {
    rawUrl = originalNode.website || "";
  }

  let cleanDomain = "invalid";
  if (rawUrl) {
    // Pure string manipulation to extract domain (bypasses n8n URL sandbox issues)
    cleanDomain = rawUrl
      .replace(/^(?:https?:\/\/)?(?:www\.)?/i, "") // Removes http://, https://, and www.
      .split('/')[0]                               // Removes paths (e.g., /store/apps)
      .split('?')[0]                               // Removes URL parameters (e.g., ?ref=...)
      .split('#')[0];                              // Removes anchor tags
  }

  // Skip blocked domains (app stores, social media, link aggregators, etc.)
  const domainLower = cleanDomain.toLowerCase();
  const isBlocked = domainLower === 'invalid' || BLOCKED_PATTERNS.some(p => domainLower.includes(p));
  if (isBlocked) continue;

  let topicsArray = (originalNode.topics?.edges || []).map(t => t.node.name);

  // Map through the makers array to extract names, defaulting to an empty array if missing
  let makersArray = (originalNode.makers || []).map(m => m.name);

  results.push({
    json: {
      product_name: originalNode.name,
      tagline: originalNode.tagline,
      description: originalNode.description || "",
      original_ph_url: originalNode.website,
      clean_url: rawUrl,
      domain: cleanDomain,
      topics: topicsArray.join(', '),
      makers: makersArray.join(', ') // Joins multiple makers with a comma
    }
  });
}

return results;

