parameters.jsCode:
// 1. Create an object to store our grouped data, keyed by the SOURCE domain
const domainGroups = {};

// 2. Loop through all incoming items (from the Apify scraper node)
for (const item of $input.all()) {
  // Grab the specific "sourceUrl" field from your Apify output
  let rawUrl = item.json.sourceUrl || '';
  let sourceDomain = rawUrl
    .replace(/^(?:https?:\/\/)?(?:www\.)?/i, "")
    .split('/')[0]
    .split('?')[0]
    .split('#')[0]
    .toLowerCase()
    .trim();

  if (!sourceDomain) continue;

  // Initialize the Set for this domain
  if (!domainGroups[sourceDomain]) {
    domainGroups[sourceDomain] = new Set();
  }

  // Add emails to the Set
  const emails = item.json.emails || [];
  if (Array.isArray(emails) && emails.length > 0) {
    for (let email of emails) {
      if (email) domainGroups[sourceDomain].add(email.toLowerCase().trim());
    }
  }
}

// 3. Pull ALL product items from the first "Code in JavaScript" node
const productItems = $('Prepare Data for Analysis').all();
const finalResults = [];

// 4. Build the final output, ONLY keeping products that actually have emails
for (const p of productItems) {
  const product = p.json;
  const domain = (product.domain || '').toLowerCase().trim();

  if (!domain || domain === 'invalid') continue;

  // 🔥 THE FIX: If we didn't find any emails for this domain, skip it entirely!
  if (!domainGroups[domain] || domainGroups[domain].size === 0) {
    continue;
  }

  finalResults.push({
    json: {
      domain: domain,
      emails: Array.from(domainGroups[domain]),
      product_name: product.product_name || '',
      tagline: product.tagline || '',
      description: product.description || '',
      original_ph_url: product.original_ph_url || '',
      topics: product.topics || '',
      makers: product.makers || ''
    }
  });
}

return finalResults;
